// Java 25 - Scoped values (JEP 506, final)
// Learn: share immutable context for a call and read it with get().
static final ScopedValue<String> USER = ScopedValue.newInstance();

String currentUser() {
    return USER.get();
}

void handle() {
    ScopedValue.where(USER, "ada").run(() -> System.out.println(currentUser())); // USER is set only inside run()
}
